  ('social-worker-moex-01607', 'social-worker', 'social-worker-moex-108-694fe135', 'sub-social-worker-03', NULL, 'single_choice', '一個精確的預估（assessment）需要問一些重要的問題，關於對案主個人特性的問題，下列敘述 何者正確？', '["「什麼人或那個系統被牽涉在這個問題中？」", "「問題發生、持續時間和結果為何？」", "「案主對問題的情緒反應狀況如何？」", "「文化和社會階層如何影響問題？」"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:10+00:00", "source_pdf_sha1": "f8b10df23095", "answer_pdf_sha1": "f894a3302211", "source_family": "moex-gov-tw", "moex": {"exam_code": "108020", "c": "107", "s": "0602", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "社會工作直接服務", "year": "108", "exam_name": "108年第一次專技人員高等考試中醫師考試分階段考試、營養師、心理師、護理師、社會工作師考試", "original_question_number": 9, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
