  ('social-worker-moex-01609', 'social-worker', 'social-worker-moex-108-694fe135', 'sub-social-worker-03', NULL, 'single_choice', '有關個案工作當中的「情感轉移」（transference）現象，下列敘述何者正確？', '["當個案出現情感轉移時，容易和當下狀況疏離，影響到專業關係，無助於個案改變", "情感轉移是一種個案對專業人員的負向情緒（如：敵意、憤怒）；個案對專業人員的正向情緒 並不屬於情感轉移", "情感轉移在專業關係中不被允許，社會工作者宜協助個案即時忽略", "為協助個案回憶幼年經驗，社會工作者宜協助個案把早年對重要他人的情感，轉移到專業人員 身上"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:10+00:00", "source_pdf_sha1": "f8b10df23095", "answer_pdf_sha1": "f894a3302211", "source_family": "moex-gov-tw", "moex": {"exam_code": "108020", "c": "107", "s": "0602", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "社會工作直接服務", "year": "108", "exam_name": "108年第一次專技人員高等考試中醫師考試分階段考試、營養師、心理師、護理師、社會工作師考試", "original_question_number": 11, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-01610', 'social-worker', 'social-worker-moex-108-694fe135', 'sub-social-worker-03', NULL, 'single_choice', '關於社會資源理論強調個案的「自然支持」（natural supports）系統之敘述，下列何者錯誤？', '["個人日常的家庭網絡和社區連結屬於自然支持的一環", "鼓勵個案連結自然支持，容易造成資源的重複與浪費", "比起正式支持，自然支持更能彈性地滿足個案的需求", "自然支持和正式支持一樣，都要留意倫理問題"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:10+00:00", "source_pdf_sha1": "f8b10df23095", "answer_pdf_sha1": "f894a3302211", "source_family": "moex-gov-tw", "moex": {"exam_code": "108020", "c": "107", "s": "0602", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "社會工作直接服務", "year": "108", "exam_name": "108年第一次專技人員高等考試中醫師考試分階段考試、營養師、心理師、護理師、社會工作師考試", "original_question_number": 12, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL)
